function test_strip() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    assert($exchange->strip(' asd') === 'asd');
    assert($exchange->strip('    asd') === 'asd');
    assert($exchange->strip('asd ') === 'asd');
    assert($exchange->strip('asd    ') === 'asd');
    assert($exchange->strip(' asd ') === 'asd');
    assert($exchange->strip('    asd    ') === 'asd');
    assert($exchange->strip('asd') === 'asd');
    assert($exchange->strip('') === '');
}
